                    <div class="flow-tile" onclick="showFlow('seamless')" style="border: 2px solid var(--accent-primary); background: rgba(16, 132, 109, 0.03);">
                        <div class="tile-icon">
                            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z" fill="#404C49"/>
