                    <!-- Section: Handle Response -->
                    <div class="seamless-section" id="sm-response">
                        <h2>Step 4 &ndash; Handle PayU Response</h2>

                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After payment completion, PayU sends a callback to your surl/furl. You MUST verify the response hash server-side before fulfilling the order.</p>
                            </div>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>surl/furl Configured</strong><br>Success and failure callback URLs set in your payment request</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Server-side Hash Verification Logic</strong><br>Backend code to compute and compare the reverse hash</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Payment Hash Salt</strong><br>The same salt (v1) used during payment initiation</div>
                                    </div>
                                </div>
                            </div>

                            <!-- Flow Diagram -->
                            <div class="sm-guide-flow">
                                <h3>How It Works</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">1</div>
                                        <div class="sm-flow-label">Payment Complete<br><small>Customer pays</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">2</div>
                                        <div class="sm-flow-label">PayU Callback<br><small>POST to surl/furl</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">3</div>
                                        <div class="sm-flow-label">Verify Hash<br><small>Reverse hash check</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">4</div>
                                        <div class="sm-flow-label">Process Order<br><small>Fulfill / reject</small></div>
                                    </div>
                                </div>
                            </div>

                            <!-- Step-by-Step -->
                            <div class="sm-guide-steps">
                                <h3>Step-by-Step Guide</h3>
                                <div class="sm-numbered-steps">
                                    <div class="sm-step">
                                        <div class="sm-step-num">1</div>
                                        <div class="sm-step-content">
                                            <strong>Receive callback at surl/furl</strong>
                                            <p>PayU sends a POST request to your <code>surl</code> (on success) or <code>furl</code> (on failure) with all transaction parameters.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">2</div>
                                        <div class="sm-step-content">
                                            <strong>Extract response parameters</strong>
                                            <p>Read <code>status</code>, <code>email</code>, <code>firstname</code>, <code>productinfo</code>, <code>amount</code>, <code>txnid</code>, <code>key</code>, <code>udf1-5</code>, and the received <code>hash</code> from the POST body.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">3</div>
                                        <div class="sm-step-content">
                                            <strong>Compute reverse hash</strong>
                                            <p>Build the reverse hash string: <code>sha512(salt||||||udf5|udf4|udf3|udf2|udf1|email|firstname|productinfo|amount|txnid|key|status)</code>. Note the reversed order with salt first and status last.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">4</div>
                                        <div class="sm-step-content">
                                            <strong>Compare hashes</strong>
                                            <p>Compare your computed hash with the <code>hash</code> received in the response. They must match exactly (case-insensitive).</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">5</div>
                                        <div class="sm-step-content">
                                            <strong>Fulfill or reject order</strong>
                                            <p>If hashes match and <code>status=success</code>, fulfill the order. If hashes don't match, treat the response as tampered and reject. Always call <code>verify_payment</code> API as an additional check.</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <h3>Key Response Parameters</h3>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>mihpayid</code></td><td>PayU's unique transaction ID</td><td>403993715536330700</td></tr>
                                <tr><td><code>status</code></td><td>Transaction status</td><td>success / failure / pending</td></tr>
                                <tr><td><code>txnid</code></td><td>Your transaction ID</td><td>TXN_1234567890</td></tr>
                                <tr><td><code>amount</code></td><td>Transaction amount</td><td>10.00</td></tr>
                                <tr><td><code>hash</code></td><td>Response hash for verification</td><td>(SHA-512 hash)</td></tr>
                                <tr><td><code>mode</code></td><td>Payment mode used</td><td>UPI</td></tr>
                                <tr><td><code>unmappedstatus</code></td><td>Detailed status from bank</td><td>captured</td></tr>
                                <tr><td><code>error_Message</code></td><td>Error details if failed</td><td>No Error</td></tr>
                            </tbody>
                        </table>
                        <h3>Response Hash Verification</h3>
                        <div class="sm-info-box warning">
                            <strong>Critical: Always verify the response hash!</strong>
                            <p>The reverse hash formula is the mirror of the payment hash. Never trust a response without verifying the hash.</p>
                        </div>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Reverse Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>// Reverse hash formula (for response verification):
sha512(SALT||||||udf5|udf4|udf3|udf2|udf1|email|firstname|productinfo|amount|txnid|key|status)

// Note: The order is REVERSED compared to payment hash
// SALT comes first, and status is appended at the end</code></pre>
                        </div>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Node.js &ndash; Verify Response</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>function verifyPayUResponse(response, salt) {
    const { status, email, firstname, productinfo, amount, txnid, key } = response;
    const udf1='', udf2='', udf3='', udf4='', udf5='';
    
    const reverseHashString = `${salt}||||||${udf5}|${udf4}|${udf3}|${udf2}|${udf1}|${email}|${firstname}|${productinfo}|${amount}|${txnid}|${key}|${status}`;
    const calculatedHash = crypto.createHash('sha512').update(reverseHashString).digest('hex');
    
    if (calculatedHash === response.hash) {
        console.log('Response verified! Payment is authentic.');
        return true;
    } else {
        console.error('HASH MISMATCH! Response may be tampered.');
        return false;
    }
}</code></pre>
