                        <!-- Response Handling Code Example -->
                        <h3>Response Handling Logic</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Node.js &ndash; Verify + Extract mihpayid</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>const result = await verifyPayment(key, salt, txnId);
const txnDetails = result.transaction_details;

if (txnDetails) {
    const txn = Object.values(txnDetails)[0];
    const mihpayid = txn.mihpayid;
    const mode = txn.mode;          // "UPI", "CC", "DC", "ENACH"
    const status = txn.status;       // "success", "failure", "pending"
    const paymentSource = txn.payment_source; // "sist" for mandate

    if (paymentSource === "sist" &amp;&amp; mode === "UPI" &amp;&amp; status === "success") {
        // Store mihpayid as authPayuIdforUPI for recurring payments
        console.log("UPI Mandate verified:", mihpayid);
    }
}</code></pre>
