                    <!-- Section: Troubleshooting -->
                    <div class="seamless-section" id="sm-troubleshoot">
                        <h2>Troubleshooting</h2>
                        <p>Common issues developers face during UPI seamless integration and how to fix them.</p>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Common issues developers encounter during PayU UPI seamless integration. Each issue includes causes, detection methods, and step-by-step fixes.</p>
                            </div>

                            <div class="sm-guide-prereqs">
                                <h3>Key Concepts</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Hash Validation</strong><br>Ensure correct formula and salt</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>VPA Format</strong><br>Must be user@handle format</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>S2S Flow</strong><br>Always use txn_s2s_flow=4 for Intent</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Polling Strategy</strong><br>verify_payment every 5-10s for pending</div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-guide-flow">
                                <h3>Quick Diagnostic</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">1</div>
                                        <div class="sm-flow-label">Error Message<br><small>Read the error</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">2</div>
                                        <div class="sm-flow-label">Identify Category<br><small>Hash / VPA / Flow</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">3</div>
                                        <div class="sm-flow-label">Follow Fix Steps<br><small>See accordion below</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">4</div>
                                        <div class="sm-flow-label">Re-test<br><small>Validate the fix</small></div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div class="sm-accordion">
                            <div class="sm-accordion-item">
                                <button class="sm-accordion-header" onclick="smToggleAccordion(this)">
                                    <span class="sm-acc-icon error-icon">&#10060;</span>
                                    <strong>Hash Mismatch Error</strong>
                                    <span class="sm-acc-arrow">&#9660;</span>
                                </button>
                                <div class="sm-accordion-body">
                                    <h4>Causes</h4>
                                    <ul>
                                        <li>Incorrect salt being used (use Salt v1, not v2)</li>
                                        <li>Wrong parameter order in hash string</li>
                                        <li>Extra spaces or encoding issues in parameters</li>
                                        <li>Missing pipe characters (need exactly 6 pipes before salt: <code>||||||</code>)</li>
                                        <li>Amount format mismatch (e.g., "10" vs "10.00")</li>
                                    </ul>
                                    <h4>How to Detect</h4>
                                    <p>PayU returns error message <code>"Hash validation failed"</code> or <code>"Sorry, Some Problem Occurred"</code>.</p>
                                    <h4>How to Fix</h4>
                                    <div class="sm-code-block">
                                        <div class="sm-code-header"><span>Debug Hash</span><button onclick="smCopyCode(this)">Copy</button></div>
                                        <pre><code>// Print the hash string before hashing to verify:
const hashString = `${key}|${txnid}|${amount}|${productinfo}|${firstname}|${email}|${udf1}|${udf2}|${udf3}|${udf4}|${udf5}||||||${salt}`;
console.log('Hash Input:', hashString);  // Verify each component
console.log('Pipe count:', (hashString.match(/\|/g)||[]).length); // Should be 17</code></pre>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-accordion-item">
                                <button class="sm-accordion-header" onclick="smToggleAccordion(this)">
                                    <span class="sm-acc-icon error-icon">&#10060;</span>
                                    <strong>Invalid UPI Handle / VPA</strong>
                                    <span class="sm-acc-arrow">&#9660;</span>
                                </button>
                                <div class="sm-accordion-body">
                                    <h4>Causes</h4>
                                    <ul>
                                        <li>Wrong VPA format (must be <code>username@handle</code>)</li>
                                        <li>Invalid UPI handle (e.g., non-existent bank handle)</li>
                                        <li>Bank-side rejection or temporarily unavailable handle</li>
                                    </ul>
                                    <h4>How to Detect</h4>
                                    <p>Validate VPA API returns <code>isVPAValid: 0</code>.</p>
                                    <h4>How to Fix</h4>
                                    <p>Always call the <code>validateVPA</code> API before initiating payment. Show user-friendly error if VPA is invalid.</p>
                                </div>
                            </div>

                            <div class="sm-accordion-item">
                                <button class="sm-accordion-header" onclick="smToggleAccordion(this)">
                                    <span class="sm-acc-icon warning-icon">&#9888;</span>
                                    <strong>Payment Stuck in Pending</strong>
                                    <span class="sm-acc-arrow">&#9660;</span>
                                </button>
                                <div class="sm-accordion-body">
                                    <h4>Causes</h4>
                                    <ul>
                                        <li>UPI collect request timed out (customer didn't approve in time)</li>
                                        <li>Bank-side processing delay</li>
                                        <li>Network timeout between UPI switch and bank</li>
                                    </ul>
                                    <h4>How to Detect</h4>
                                    <p>Verify API returns <code>status: "pending"</code> or <code>unmappedstatus: "pending"</code>.</p>
                                    <h4>How to Fix</h4>
                                    <ul>
                                        <li>Implement polling: Check payment status every 5-10 seconds for up to 5 minutes</li>
                                        <li>Set UPI expiry time in the request using <code>expiryTime</code> parameter</li>
                                        <li>Show appropriate "Payment Processing" UI to the customer</li>
                                    </ul>
                                </div>
                            </div>

                            <div class="sm-accordion-item">
                                <button class="sm-accordion-header" onclick="smToggleAccordion(this)">
                                    <span class="sm-acc-icon warning-icon">&#9888;</span>
                                    <strong>Deeplink / QR Code Not Working</strong>
                                    <span class="sm-acc-arrow">&#9660;</span>
                                </button>
                                <div class="sm-accordion-body">
                                    <h4>Causes</h4>
                                    <ul>
                                        <li>Deeplink URL expired (usually valid for 5 minutes)</li>
                                        <li>QR code generated from incorrect deeplink</li>
                                        <li>UPI app not installed on device (for specific intent)</li>
                                    </ul>
                                    <h4>How to Fix</h4>
                                    <ul>
                                        <li>Generate fresh deeplink for each attempt</li>
                                        <li>Use Generic Intent (<code>INTENT</code>) for web to let any UPI app scan</li>
                                        <li>Show fallback option if specific UPI app is not available</li>
                                    </ul>
                                </div>
                            </div>

                            <div class="sm-accordion-item">
                                <button class="sm-accordion-header" onclick="smToggleAccordion(this)">
                                    <span class="sm-acc-icon error-icon">&#10060;</span>
                                    <strong>txn_s2s_flow Parameter Missing</strong>
                                    <span class="sm-acc-arrow">&#9660;</span>
                                </button>
                                <div class="sm-accordion-body">
                                    <h4>Causes</h4>
                                    <ul>
                                        <li>Forgot to include <code>txn_s2s_flow=4</code> in the request</li>
                                        <li>Using wrong value (must be <code>4</code> for UPI Intent S2S)</li>
                                    </ul>
                                    <h4>How to Detect</h4>
                                    <p>PayU redirects to its payment page instead of returning a deeplink, or returns an error.</p>
                                    <h4>How to Fix</h4>
                                    <p>Always include <code>txn_s2s_flow=4</code> in your payment request for UPI Intent S2S flow.</p>
                                </div>
                            </div>
                        </div>
                        <div class="sm-guide-steps" style="margin-top: 2rem;">
                            <h3>Quick Reference: Error Codes</h3>
                            <div class="sm-table-wrapper">
                                <table class="sm-reference-table">
                                    <thead>
                                        <tr>
                                            <th>Error</th>
                                            <th>Meaning</th>
                                            <th>Fix</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr>
                                            <td><code>Hash validation failed</code></td>
                                            <td>Incorrect hash</td>
                                            <td>Check salt version, parameter order</td>
                                        </tr>
                                        <tr>
                                            <td><code>Invalid VPA</code></td>
                                            <td>VPA doesn't exist</td>
                                            <td>Validate VPA before payment</td>
                                        </tr>
                                        <tr>
                                            <td><code>Transaction pending</code></td>
                                            <td>Awaiting customer action</td>
                                            <td>Poll verify_payment API</td>
                                        </tr>
                                        <tr>
                                            <td><code>txn_s2s_flow missing</code></td>
                                            <td>Not in S2S mode</td>
                                            <td>Add txn_s2s_flow=4</td>
                                        </tr>
                                        <tr>
                                            <td><code>Invalid amount</code></td>
                                            <td>Amount format wrong</td>
                                            <td>Use decimal format (e.g. 10.00)</td>
                                        </tr>
                                    </tbody>
                                </table>
                            </div>
                        </div>

